import { useState } from 'react';
import { Header } from './components/Header';
import { InputForm } from './components/InputForm';
import { ResultsDisplay } from './components/ResultsDisplay';
import { generateNames } from './services/geminiService';
import { Style, NameCandidate } from './types';

function App() {
  const [candidates, setCandidates] = useState<NameCandidate[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (name: string, style: Style) => {
    setIsLoading(true);
    setError(null);
    try {
      const results = await generateNames(name, style);
      setCandidates(results);
      // 결과가 나오면 결과 영역으로 부드럽게 스크롤
      setTimeout(() => {
        document.getElementById('results-section')?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (err) {
      setError('Failed to generate names. Please try again.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen font-sans selection:bg-pink-100 selection:text-pink-900 pb-20">
      <Header />

      <main className="relative container mx-auto px-4 sm:px-6 lg:px-8 mt-12">
        {/* Background Decorative Elements - Mimicking the soft petal feel */}
        <div className="absolute top-[-10%] right-[-5%] w-96 h-96 bg-pink-200/20 rounded-full blur-[100px] animate-float pointer-events-none"></div>
        <div className="absolute bottom-0 left-[-10%] w-[500px] h-[500px] bg-blue-100/20 rounded-full blur-[120px] animate-float pointer-events-none" style={{ animationDelay: '2s' }}></div>

        <div className="max-w-4xl mx-auto space-y-16">
          {/* Hero & Input Section with Enhanced Glassmorphism */}
          <section className="bg-white/30 backdrop-blur-2xl border border-white/60 rounded-[3rem] p-8 md:p-14 shadow-[0_32px_64px_-15px_rgba(0,0,0,0.05)] relative overflow-hidden">
            <div className="grid grid-cols-1 md:grid-cols-5 gap-12 items-center">
              <div className="md:col-span-3 space-y-8">
                <div className="space-y-4">
                  <h2 className="text-5xl md:text-6xl font-extrabold tracking-tight text-gray-900 leading-[1.1]">
                    Your <span className="text-transparent bg-clip-text bg-gradient-to-r from-pink-500 to-rose-400">Japanese</span> <br/>Soul Name
                  </h2>
                  <p className="text-xl text-gray-500 font-medium max-w-md">
                    AI-crafted Kanji names inspired by the elegance of Japan's changing seasons.
                  </p>
                </div>

                <div className="pt-2">
                  <InputForm onSubmit={handleGenerate} isLoading={isLoading} />
                </div>
              </div>

              <div className="hidden md:flex md:col-span-2 justify-center">
                <div className="relative w-64 h-64 md:w-80 md:h-80 flex items-center justify-center">
                  {/* Ornate decorative ring */}
                  <div className="absolute inset-0 border-[16px] border-pink-100/30 rounded-full animate-pulse"></div>
                  <div className="absolute inset-4 border-[1px] border-pink-200/50 rounded-full"></div>

                  <div className="relative bg-white/40 backdrop-blur-md border border-white p-12 rounded-[2.5rem] shadow-2xl transform hover:scale-105 transition-transform duration-700">
                    <span className="text-9xl font-serif text-gray-800 drop-shadow-sm">名</span>
                    <div className="absolute -bottom-2 -right-2 bg-gradient-to-br from-pink-400 to-rose-400 w-12 h-12 rounded-full flex items-center justify-center text-white shadow-lg">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-7.714 2.143L11 21l-2.286-6.857L1 12l7.714-2.143L11 3z" />
                      </svg>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>

          {/* Results Section */}
          <section id="results-section" className="transition-all duration-1000">
            <ResultsDisplay 
              candidates={candidates} 
              isLoading={isLoading} 
              error={error} 
            />
          </section>
        </div>
      </main>

      <footer className="mt-32 pb-12 text-center">
        <div className="inline-flex items-center gap-2 px-6 py-2 bg-white/20 backdrop-blur-sm rounded-full border border-white/40 text-gray-400 text-sm font-medium">
          <span className="w-2 h-2 bg-pink-400 rounded-full"></span>
          © 2024 Japan Name Generator AI
        </div>
      </footer>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Style } from '../types';

interface InputFormProps {
  onSubmit: (name: string, style: Style) => void;
  isLoading: boolean;
}

export const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [name, setName] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<Style>(Style.Feminine);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name.trim()) {
      onSubmit(name, selectedStyle);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-10">
      <div className="group relative">
        <label htmlFor="name" className="block text-xs font-black text-gray-400 mb-3 ml-1 uppercase tracking-[0.2em]">
          English Name
        </label>
        <input
          type="text"
          id="name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="e.g. Alice, James..."
          className="w-full px-8 py-5 bg-white/40 border-2 border-pink-50 rounded-3xl focus:ring-8 focus:ring-pink-500/5 focus:border-pink-300 focus:bg-white/80 transition-all outline-none text-2xl font-medium text-gray-800 placeholder-gray-300 shadow-inner"
          required
        />
      </div>

      <div>
        <label className="block text-xs font-black text-gray-400 mb-4 ml-1 uppercase tracking-[0.2em]">
          Preferred Aesthetic
        </label>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
          {Object.values(Style).map((style) => (
            <button
              key={style}
              type="button"
              onClick={() => setSelectedStyle(style)}
              className={`px-4 py-4 rounded-2xl font-bold transition-all duration-500 border-2 ${
                selectedStyle === style
                  ? 'bg-gradient-to-br from-rose-500 to-pink-500 border-transparent text-white shadow-[0_10px_30px_-10px_rgba(244,63,94,0.5)] scale-105 z-10'
                  : 'bg-white/30 border-white/50 text-gray-500 hover:border-pink-200 hover:text-rose-400'
              }`}
            >
              {style}
            </button>
          ))}
        </div>
      </div>

      <button
        type="submit"
        disabled={isLoading || !name.trim()}
        className="group w-full relative overflow-hidden bg-gray-900 text-white font-bold text-lg py-6 px-8 rounded-3xl transition-all hover:bg-black active:scale-[0.98] disabled:opacity-50 disabled:pointer-events-none shadow-2xl shadow-gray-200"
      >
        <div className="relative z-10 flex items-center justify-center gap-4">
          {isLoading ? (
            <>
              <svg className="animate-spin h-6 w-6 text-white" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              <span>GENERATING...</span>
            </>
          ) : (
            <>
              <span>REVEAL MY KANJI</span>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
              </svg>
            </>
          )}
        </div>
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full group-hover:animate-shimmer"></div>
      </button>
    </form>
  );
};

import React from 'react';

export const Header: React.FC = () => {
  return (
    <header className="bg-white/20 backdrop-blur-xl sticky top-0 z-50 border-b border-white/40">
      <div className="container mx-auto px-4 py-4 flex items-center justify-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-rose-500 rounded-lg rotate-12 flex items-center justify-center text-white font-serif text-lg">名</div>
          <h1 className="text-xl md:text-2xl font-black text-gray-800 tracking-tight">
            Kanji<span className="text-rose-500">Gen</span>
          </h1>
        </div>
      </div>
    </header>
  );
};
